import { useEffect, useState } from "react";
import { Skeleton } from "@/components/ui/skeleton";

interface ActivityListSkeletonProps {
  count?: number;
}

const useResponsiveCount = (fallback: number) => {
  const [count, setCount] = useState(fallback);
  useEffect(() => {
    const calc = () => {
      if (typeof window === "undefined") return;
      // matches grid: md:grid-cols-2
      setCount(window.innerWidth >= 768 ? 4 : 2);
    };
    calc();
    window.addEventListener("resize", calc);
    return () => window.removeEventListener("resize", calc);
  }, []);
  return count;
};

const ActivityListSkeleton = ({ count }: ActivityListSkeletonProps) => {
  const responsive = useResponsiveCount(4);
  const finalCount = count ?? responsive;
  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-6">
      {Array.from({ length: finalCount }).map((_, i) => (
        <div key={i} className="rounded-lg border border-border overflow-hidden bg-card">
          {/* Image skeleton with badge */}
          <div className="relative">
            <Skeleton className="w-full h-48 sm:h-56 rounded-none" />
            <Skeleton className="absolute top-3 left-3 h-6 w-20 rounded-full" />
          </div>
          
          {/* Content */}
          <div className="p-4 sm:p-5">
            {/* Title */}
            <Skeleton className="h-7 w-3/4 mb-2" />
            
            {/* Date range */}
            <Skeleton className="h-4 w-48 mb-3" />
            
            {/* Description */}
            <Skeleton className="h-4 w-full mb-1" />
            <Skeleton className="h-4 w-5/6 mb-4" />
            
            {/* Stats row */}
            <div className="flex items-center gap-4 mb-4">
              <Skeleton className="h-5 w-24" />
              <Skeleton className="h-5 w-20" />
            </div>
            
            {/* Actions */}
            <div className="flex gap-2">
              <Skeleton className="h-9 flex-1 rounded-md" />
              <Skeleton className="h-9 w-9 rounded-md" />
              <Skeleton className="h-9 w-9 rounded-md" />
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ActivityListSkeleton;
