import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Languages, Loader2, RotateCcw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface TranslateAllButtonProps {
  /** Array of { id, text } items to translate in batch */
  items: { id: string; text: string }[];
  /** Callback with map of id -> translatedText, or null to reset */
  onTranslations: (translations: Record<string, string> | null) => void;
  className?: string;
}

// Global cache keyed by lang + content hash
const batchCache = new Map<string, Record<string, string>>();

const TranslateAllButton = ({ items, onTranslations, className }: TranslateAllButtonProps) => {
  const { t, i18n } = useTranslation();
  const [isTranslating, setIsTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(false);

  const handleTranslate = async () => {
    if (showTranslation) {
      setShowTranslation(false);
      onTranslations(null);
      return;
    }

    if (!items || items.length === 0) return;

    const targetLang = i18n.language;
    
    // Build a combined text with separators for batch translation
    const separator = "\n---ITEM_SEPARATOR---\n";
    const combinedText = items.map(item => item.text).join(separator);
    const cacheKey = `batch_${targetLang}_${combinedText.substring(0, 200)}_${items.length}`;

    // Check cache
    const cached = batchCache.get(cacheKey);
    if (cached) {
      setShowTranslation(true);
      onTranslations(cached);
      return;
    }

    setIsTranslating(true);
    try {
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: { 
          text: combinedText, 
          targetLang 
        }
      });

      if (error) {
        console.error('Batch translation error:', error);
        toast.error(t("translate.error", "翻译失败，请稍后重试"));
        return;
      }

      if (data?.translatedText) {
        // Split the translated text back into individual items
        const translatedParts = data.translatedText.split(/---ITEM_SEPARATOR---/);
        const translationMap: Record<string, string> = {};
        
        items.forEach((item, index) => {
          translationMap[item.id] = (translatedParts[index] || item.text).trim();
        });

        batchCache.set(cacheKey, translationMap);
        setShowTranslation(true);
        onTranslations(translationMap);
        toast.success(t("translate.success", "翻译完成"));
      } else if (data?.error) {
        toast.error(data.error);
      }
    } catch (err) {
      console.error('Batch translation error:', err);
      toast.error(t("translate.error", "翻译失败，请稍后重试"));
    } finally {
      setIsTranslating(false);
    }
  };

  return (
    <Button
      variant="outline"
      size="sm"
      className={`gap-1.5 ${className || ''}`}
      onClick={handleTranslate}
      disabled={isTranslating || items.length === 0}
    >
      {isTranslating ? (
        <>
          <Loader2 className="h-4 w-4 animate-spin" />
          <span>{t("translate.translating", "翻译中...")}</span>
        </>
      ) : showTranslation ? (
        <>
          <RotateCcw className="h-4 w-4" />
          <span>{t("translate.showOriginal", "显示原文")}</span>
        </>
      ) : (
        <>
          <Languages className="h-4 w-4" />
          <span>{t("translate.translateAll", "翻译全文")}</span>
        </>
      )}
    </Button>
  );
};

export default TranslateAllButton;
