import { useCallback, useMemo, useState } from "react";
import TranslateAllButton from "@/components/TranslateAllButton";
import { Card, CardContent, CardFooter, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Calendar, Clock, Users, UtensilsCrossed, ShoppingBag, UserCircle, Forward, List, LayoutGrid } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { useActivities, useSubscriptions, ActivityCreator } from "@/hooks/useActivities";
import { useActivitiesListRealtime } from "@/hooks/useActivityRealtime";
import { useAuth } from "@/contexts/AuthContext";
import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { format } from "date-fns";
import { useInfiniteScroll } from "@/hooks/useInfiniteScroll";
import i18n from "@/i18n/config";
import platformLogo from "@/assets/xiaoxiong-logo-v3.png";
import { ActivityListSkeleton } from "@/components/skeletons";
import { ActivityFavoriteButton } from "@/components/ActivityFavoriteButton";
import { PullToRefresh } from "@/components/PullToRefresh";
import { useQueryClient } from "@tanstack/react-query";
import { useIsMobile } from "@/hooks/use-mobile";


const getLocalizedRestaurantName = (restaurant: ActivityCreator["restaurant"]) => {
  if (!restaurant) return "";
  const lang = i18n.language;
  if (lang === "zh") return restaurant.name;
  if (lang === "pt") return restaurant.name_pt || restaurant.name_en || restaurant.name;
  return restaurant.name_en || restaurant.name;
};

const Activities = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { localizeActivity } = useLocalizedContent();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const isMobile = useIsMobile();

  // Mobile layout state: 1 or 2 columns
  const [mobileColumns, setMobileColumns] = useState<1 | 2>(() => {
    const saved = localStorage.getItem('activity-mobile-columns');
    return (saved === '2' ? 2 : 1) as 1 | 2;
  });
  const [translations, setTranslations] = useState<Record<string, string> | null>(null);

  const toggleMobileColumns = () => {
    const newColumns = mobileColumns === 1 ? 2 : 1;
    setMobileColumns(newColumns);
    localStorage.setItem('activity-mobile-columns', String(newColumns));
  };

  // Enable realtime updates for activities list
  useActivitiesListRealtime();

  const { data: activitiesData, isLoading } = useActivities();
  const { data: subscriptions = [] } = useSubscriptions();
  const subscribedIds = subscriptions.map(sub => sub.activity_id);

  // Filter to only show published activities (draft activities should never show to frontend users)
  const activities = activitiesData?.filter(activity => 
    activity.status === "published" && activity.visible === true
  );

  // Infinite scroll for activities
  const { displayedData: displayedActivities, hasMore, loadMore } = useInfiniteScroll({
    data: activities,
    initialItemsPerPage: 6,
    incrementPerPage: 6,
  });

  // Prepare translation items from displayed activities
  const translateItems = useMemo(() => 
    displayedActivities.map(activity => {
      const loc = localizeActivity(activity);
      return { id: activity.id, text: `${loc.title}\n${loc.content}` };
    }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [displayedActivities]
  );

  // Pull-to-refresh handler - clears cache and forces fresh data
  const handleRefresh = useCallback(async () => {
    // Clear caches first to ensure fresh data
    queryClient.removeQueries({ queryKey: ['activities'] });
    queryClient.removeQueries({ queryKey: ['subscriptions'] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['activities'] }),
      queryClient.invalidateQueries({ queryKey: ['subscriptions'] }),
    ]);
  }, [queryClient]);

  return (
    <PullToRefresh onRefresh={handleRefresh}>
      <div className="min-h-screen bg-secondary/20 py-8 px-4 animate-fade-in">
        <div className="container mx-auto max-w-7xl">
          {/* Header */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-2">
            <h1 className="text-3xl sm:text-4xl font-medium text-primary">
              {t("activities.title")}
            </h1>
            <div className="flex items-center gap-2">
              <TranslateAllButton
                items={translateItems}
                onTranslations={setTranslations}
              />
              {/* Mobile layout toggle - only show on mobile */}
              {isMobile && (
                <div className="inline-flex h-9 items-center justify-center rounded-md bg-muted p-1 text-muted-foreground">
                  <button 
                    onClick={toggleMobileColumns}
                    title={mobileColumns === 1 
                      ? t("activities.doubleColumn", "双列布局") 
                      : t("activities.singleColumn", "单列布局")}
                    className="inline-flex items-center justify-center whitespace-nowrap rounded-sm px-2.5 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 bg-background text-foreground shadow-sm"
                  >
                    {mobileColumns === 1 ? (
                      <LayoutGrid className="h-3.5 w-3.5" />
                    ) : (
                      <List className="h-3.5 w-3.5" />
                    )}
                  </button>
                </div>
              )}
            </div>
          </div>
          <p className="text-muted-foreground text-base sm:text-lg">{t("activities.description")}</p>
        </div>

        {/* Loading State */}
        {isLoading && (
          <ActivityListSkeleton count={4} />
        )}

        {/* Empty State */}
        {!isLoading && (!activities || activities.length === 0) && (
          <div className="text-center py-20">
            <p className="text-xl text-muted-foreground">
              {t("activities.noActivities") || "No activities available"}
            </p>
          </div>
        )}

        {/* Activities Grid */}
        {!isLoading && activities && activities.length > 0 && (
          <>
            <div className={`grid gap-6 ${mobileColumns === 2 ? 'grid-cols-2' : 'grid-cols-1'} md:grid-cols-2`}>
            {displayedActivities.map((activity) => {
              const localizedActivity = localizeActivity(activity);
              // Get translated text if available
              const translatedTitle = translations?.[activity.id]?.split('\n')[0];
              const translatedContent = translations?.[activity.id]?.split('\n').slice(1).join('\n');
              // Compact mode: mobile + 2 columns
              const isCompactMode = isMobile && mobileColumns === 2;
              
              return (
                <Card key={activity.id} className={`overflow-hidden hover:shadow-large transition-shadow flex flex-col h-full ${isCompactMode ? 'gap-0' : ''}`}>
                  <Link to={`/activity/${activity.id}`} className="flex flex-col h-full">
                    <div className={`relative overflow-hidden ${isCompactMode ? 'h-28' : 'h-48'}`}>
                      {activity.media_type === "video" && activity.video_url ? (
                        <video
                          src={activity.video_url}
                          poster={activity.image_url || undefined}
                          className="w-full h-full object-cover transition-transform hover:scale-105"
                          muted
                          loop
                          playsInline
                          autoPlay
                        />
                      ) : (
                        <img
                          src={activity.image_url || "https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=600&q=80"}
                          alt={localizedActivity.title}
                          className="w-full h-full object-cover transition-transform hover:scale-105"
                        />
                      )}
                      {activity.pinned && (
                        <Badge className={`absolute ${isCompactMode ? 'top-1.5 left-1.5 text-[10px] px-1.5 py-0' : 'top-3 left-3'} bg-accent`}>
                          {t("activities.pinned")}
                        </Badge>
                      )}
                      {/* Service Type Badge - hide in compact mode */}
                      {!isCompactMode && activity.service_type && (
                        <Badge 
                          className="absolute bottom-3 left-3 flex items-center gap-1"
                          variant="secondary"
                        >
                          {activity.service_type === "dine_in" && <UtensilsCrossed className="w-3 h-3" />}
                          {activity.service_type === "takeaway" && <ShoppingBag className="w-3 h-3" />}
                          {activity.service_type === "both" && (
                            <>
                              <UtensilsCrossed className="w-3 h-3" />
                              <ShoppingBag className="w-3 h-3" />
                            </>
                          )}
                          {t(`activities.serviceType.${activity.service_type}`)}
                        </Badge>
                      )}
                      {activity.end_date && new Date(activity.end_date) < new Date() ? (
                        <Badge className={`absolute ${isCompactMode ? 'top-1.5 right-1.5 text-[10px] px-1.5 py-0' : 'top-3 right-3'} bg-secondary`}>
                          {t("activities.ended")}
                        </Badge>
                      ) : (
                        <div className={`absolute ${isCompactMode ? 'top-1.5 right-1.5' : 'top-3 right-3'} flex gap-1`}>
                          {activity.subscriber_count !== undefined && (
                            <Badge variant="secondary" className={`flex items-center gap-0.5 ${isCompactMode ? 'text-[10px] px-1 py-0' : 'gap-1'}`}>
                              <Users className={isCompactMode ? 'w-2.5 h-2.5' : 'w-3 h-3'} />
                              <span>{activity.subscriber_count}</span>
                            </Badge>
                          )}
                          {!isCompactMode && activity.share_count !== undefined && activity.share_count > 0 && (
                            <Badge variant="secondary" className="flex items-center gap-1">
                              <Forward className="w-3 h-3" />
                              <span>{activity.share_count}</span>
                            </Badge>
                          )}
                        </div>
                      )}
                    </div>

                    <CardHeader className={isCompactMode ? 'p-2 pb-1' : ''}>
                      <h3 className={`font-semibold text-card-foreground line-clamp-2 ${isCompactMode ? 'text-sm' : 'text-xl'}`}>
                        {translatedTitle || localizedActivity.title}
                      </h3>
                    </CardHeader>

                    <CardContent className={`flex-1 ${isCompactMode ? 'p-2 pt-0 space-y-1' : 'space-y-3'}`}>
                      {/* Content - hide in compact mode */}
                      {!isCompactMode && (
                        <div 
                          className="text-muted-foreground text-sm line-clamp-3
                            [&_h1]:text-base [&_h1]:font-bold [&_h1]:text-foreground
                            [&_h2]:text-sm [&_h2]:font-semibold [&_h2]:text-foreground
                            [&_h3]:text-sm [&_h3]:font-medium [&_h3]:text-foreground
                            [&_strong]:font-semibold [&_strong]:text-foreground
                            [&_p]:my-1
                            [&_ul]:list-disc [&_ul]:ml-4
                            [&_ol]:list-decimal [&_ol]:ml-4
                            [&_*]:!text-inherit"
                          dangerouslySetInnerHTML={{ __html: translatedContent || localizedActivity.content }}
                        />
                      )}
                      
                      {activity.start_date && (
                        <div className={`flex items-center gap-1 text-muted-foreground ${isCompactMode ? 'text-xs' : 'gap-2 text-sm'}`}>
                          <Calendar className={isCompactMode ? 'w-3 h-3' : 'w-4 h-4'} />
                          <span>{format(new Date(activity.start_date), isCompactMode ? "MM/dd" : "PPP")}</span>
                        </div>
                      )}

                      {/* End date - hide in compact mode */}
                      {!isCompactMode && activity.end_date && (
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <Clock className="w-4 h-4" />
                          <span>{t("activities.until")} {format(new Date(activity.end_date), "PPP")}</span>
                        </div>
                      )}

                      {/* Creator Info - hide in compact mode */}
                      {!isCompactMode && (
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <UserCircle className="w-4 h-4" />
                          <span>{t("activities.creatorLabel")}</span>
                          {activity.creator?.isAdmin ? (
                            <div className="flex items-center gap-1">
                              <img src={platformLogo} alt="Platform" className="w-4 h-4 rounded-full object-contain" />
                              <span className="font-medium">{t("activities.createdByPlatform")}</span>
                            </div>
                          ) : activity.creator?.restaurant ? (
                            <div 
                              className="flex items-center gap-1 cursor-pointer"
                              onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                navigate(`/restaurant/${activity.creator.restaurant!.id}`);
                              }}
                            >
                              {activity.creator.avatar_url ? (
                                <Avatar className="w-4 h-4">
                                  <AvatarImage src={activity.creator.avatar_url} alt="Creator" />
                                  <AvatarFallback className="text-[8px]">
                                    {activity.creator.restaurant.name.charAt(0)}
                                  </AvatarFallback>
                                </Avatar>
                              ) : (
                                <div className="w-4 h-4 rounded-full bg-muted flex items-center justify-center">
                                  <span className="text-[8px] font-medium">
                                    {activity.creator.restaurant.name.charAt(0)}
                                  </span>
                                </div>
                              )}
                              <span className="text-primary font-medium hover:underline">
                                {getLocalizedRestaurantName(activity.creator.restaurant)}
                              </span>
                            </div>
                          ) : (
                            <div className="flex items-center gap-1">
                              <img src={platformLogo} alt="Platform" className="w-4 h-4 rounded-full object-contain" />
                              <span className="font-medium">{t("activities.createdByPlatform")}</span>
                            </div>
                          )}
                        </div>
                      )}
                    </CardContent>

                    <CardFooter className={`${isCompactMode ? 'p-2 pt-0' : 'gap-2'}`}>
                      <Button asChild className={`flex-1 ${isCompactMode ? 'h-7 text-xs' : ''}`} size={isCompactMode ? 'sm' : 'default'}>
                        <span>{t("activities.viewDetails")}</span>
                      </Button>
                      {!isCompactMode && (
                        <ActivityFavoriteButton 
                          activityId={activity.id}
                          initialSubscribed={subscribedIds.includes(activity.id)}
                        />
                      )}
                    </CardFooter>
                  </Link>
                </Card>
              );
            })}
          </div>
            
            {/* Load More Button */}
            {hasMore && (
              <div className="flex justify-center mt-8">
                <Button onClick={loadMore} size="lg" variant="outline">
                  {t("common.loadMore")} ({displayedActivities.length} / {activities.length})
                </Button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
    </PullToRefresh>
  );
};

export default Activities;
